  ('aboriginal-c5fb3965-moex-00168', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族基本法之規定，政府或私人於某些土地上從事土地開發、資源利用、生態保育及學術研 究，應諮商並取得原住民族或部落同意或參與，原住民得分享相關利益。以下那一種類土地不屬之？', '["原住民傳統領域土地", "原住民保留地", "部落及其周邊一定範圍內之公有土地", "部落及其周邊一定範圍內之私有土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00169', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據姓名條例的規定，關於原住民之姓氏，以下敘述何者有誤？', '["原住民之姓名登記，依其文化慣俗為之；其已依漢人姓名登記者，得申請回復其傳統姓名；回復傳 統姓名者，得申請回復原有漢人姓名", "原住民申請回復其傳統姓名或申請回復原有漢人姓名，無次數之限制", "原住民之傳統姓名或漢人姓名，均得以傳統姓名之羅馬拼音並列登記", "原住民因改漢姓造成家族姓氏誤植得申請改姓"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00170', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據森林法規定，原住民可以在原住民族傳統領域土地內的國有林或公有林依其生活慣俗需要採取森 林產物，以下何者非屬原住民族依生活慣俗採取森林產物規則內所列的生活慣俗？', '["有關農、林、漁、牧生產活動，傳統社會制度運作及傳統宗教信仰之祭祀禮儀行為", "有關出生禮、命名禮、成年禮、婚禮、喪禮及其他因各生命階段變動而舉行之禮俗行為", "有關日常生活中食、衣、住、行、育、樂、醫藥等行為", "有關日常生活中之買賣行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00171', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據行政院組織法與中央行政機關組織基準法相關規定，原住民族委員會屬於何種行政組織？', '["中央一級行政機關", "中央一級內部單位", "中央二級行政機關", "中央二級內部單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00172', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '以下何者不屬於原住民保留地禁伐補償條例之立法目的？', '["國土保安、涵養水資源", "經濟穩定、確保充分就業", "綠化環境、自然生態保育", "因應氣候變遷、減輕天然災害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00173', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於原住民族委員會補助原住民族地區基本設施維持費，以下敘述何者錯誤？', '["補助對象為轄有原住民族地區之鄉（鎮、市、區）公所", "基本設施維持費之分配包括基本分配額度、績效分配額度", "基本設施維持費之支用項目不包括辦理歲時祭儀之補助", "基礎設施維護及小型工程，其設施地點以原住民聚居地區為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00174', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '直轄市及轄有原住民族地區之縣，其直轄市、縣政府為辦理原住民族事務，以下敘述何者正確？', '["得視實際需要設原住民族專責單位辦理", "得視實際需要由社福單位協助辦理", "其原住民族專責單位之首長應具原住民身分", "其協辦之社福單位之首長應具原住民身分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00175', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '以下何者不屬於原住民（族）地區之範圍？', '["新北市烏來區", "屏東縣潮州鎮", "南投縣魚池鄉", "花蓮縣花蓮市"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00176', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '行政院於民國91年核定原住民地區範圍，是基於以下那一個法律規定之要求？', '["原住民族工作權保障法", "原住民族教育法", "原住民族基本法", "地方制度法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00177', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '我國已經立法院三讀立法通過之原住民族相關法律，以下何者正確？', '["原住民族語言發展法", "原住民民族別認定法", "原住民族土地及海域法", "原住民族自治法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
